	var outputBytes []byte
	if outputBytes, err = io.ReadAll(jqStdout); err != nil {
		aliyunCmd.Wait() // Cleanup
		jqCmd.Wait()    // Cleanup
		return "", fmt.Errorf("failed to read jq output: %w", err)
	}

	// Wait for both commands to finish
	if err := aliyunCmd.Wait(); err != nil {
		jqCmd.Wait() // Cleanup
		return string(outputBytes), fmt.Errorf("aliyun command failed: %w", err)
	}
	if err := jqCmd.Wait(); err != nil {
		return string(outputBytes), fmt.Errorf("jq command failed: %w", err)
	}

	// Write to the file
	if _, err := file.Write(outputBytes); err != nil {
		return string(outputBytes), fmt.Errorf("failed to write to output file: %w", err)
	}

	// Flush to ensure data is written to disk
	if err := file.Sync(); err != nil {
		return string(outputBytes), fmt.Errorf("failed to sync output file: %w", err)
	}

	// Return the output as a string
	return string(outputBytes), nil
}

