	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	aliyunStderr := &bytes.Buffer{}
	aliyunCmd.Stderr = aliyunStderr

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	jqStdout, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for jq command: %w", err)
	}
	jqStderr := &bytes.Buffer{}
	jqCmd.Stderr = jqStderr

	// Output file for writing jq's results
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, aliyunStderr.String())
	}
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, jqStderr.String())
	}

	// Capture jq's stdout to both the file and a buffer for return
	var jqOutputBuffer bytes.Buffer
	multiWriter := io.MultiWriter(outFile, &jqOutputBuffer)
	if _, err := io.Copy(multiWriter, jqStdout); err != nil {
		return jqOutputBuffer.String(), fmt.Errorf("failed to copy jq output: %w", err)
	}

	// Wait for commands to complete
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	// Collect all stderr outputs
	var fullStderr bytes.Buffer
	if aliyunStderr.Len() > 0 {
		fullStderr.WriteString("aliyun command stderr: " + aliyunStderr.String() + "\n")
	}
