		return jqOutputBuffer.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, fullStderr.String())
	}
	if jqErr != nil {
		return jqOutputBuffer.String(), fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, fullStderr.String())
	}

	// Return the captured jq output
	return jqOutputBuffer.String(), nil
}

