package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("invalid input parameters: loadBalancerName and outputFile cannot be empty")
	}

	// Execute aliyun CLI command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun command: %w", err)
	}

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Execute jq to filter results
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout

	jqStdout, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for jq command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Write jq output to file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	if _, err := io.Copy(outFile, jqStdout); err != nil {
		return "", fmt.Errorf("failed to write to output file: %w", err)
	}

	// Wait for commands to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Read file content to return
	fileContent, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(fileContent), nil
}

