package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// First command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunOut, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunOut

	jqOut, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for jq command: %w", err)
	}

	// Open output file for writing
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Start commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Copy jq output to file and capture it
	var output strings.Builder
	multiWriter := io.MultiWriter(outFile, &output)
	_, err = io.Copy(multiWriter, jqOut)
	if err != nil {
		return output.String(), fmt.Errorf("failed to read jq output: %w", err)
	}

	// Wait for commands to finish
	if err := jqCmd.Wait(); err != nil {
		return output.String(), fmt.Errorf("jq command failed: %w", err)
	}

	if err := aliyunCmd.Wait(); err != nil {
		return output.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	return strings.TrimSpace(output.String()), nil
}

func main() {
	// Example usage (replace with actual values)
	result, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("Output:\n%s\n", result)
	}
}

