package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious issues
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// First command: aliyun slb DescribeLoadBalancers
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunOut, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunOut

	// Create output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()
	jqCmd.Stdout = outFile

	// Capture stderr for both commands
	var stderrStr strings.Builder
	aliyunCmd.Stderr = &stderrStr
	jqCmd.Stderr = &stderrStr

	// Start and wait for commands
	if err = aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, stderrStr.String())
	}

	if err = jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, stderrStr.String())
	}

	if err = aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderrStr.String())
	}

	if err = jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, stderrStr.String())
	}

	// Read the output file to return the result
	outputBytes, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(outputBytes), nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-slb", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("Output:\n%s\n", result)
	}
}

