// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Execute aliyun slb DescribeLoadBalancers command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunOutput, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Execute jq command with aliyun output as input
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunOutput
	jqOutput, err := jqCmd.StdoutPipe()
	if err != nil {
		aliyunCmd.Wait() // Cleanup
		return "", fmt.Errorf("failed to create stdout pipe for jq command: %w", err)
	}
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Wait() // Cleanup
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Create output file
	file, err := os.Create(outputFile)
	if err != nil {
		jqCmd.Wait()
		aliyunCmd.Wait() // Cleanup
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Copy jq output to file and capture for return
	var capturedOutput []byte
	buffer := make([]byte, 1024)
	for {
		n, err := jqOutput.Read(buffer)
		if n > 0 {
			capturedOutput = append(capturedOutput, buffer[:n]...)
			if _, writeErr := file.Write(buffer[:n]); writeErr != nil {
				jqCmd.Wait()
				aliyunCmd.Wait()
				return string(capturedOutput), fmt.Errorf("failed to write to output file: %w", writeErr)
			}
		}
		if err != nil {
			break
		}
	}

	// Wait for both commands to finish
	if err := jqCmd.Wait(); err != nil {
		aliyunCmd.Wait()
		return string(capturedOutput), fmt.Errorf("jq command failed: %w", err)
	}
	if err := aliyunCmd.Wait(); err != nil {
		return string(capturedOutput), fmt.Errorf("aliyun command failed: %w", err)
	}

	return string(capturedOutput), nil
}

