package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious issues
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Create output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// First command: aliyun slb DescribeLoadBalancers
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}

	// Second command: jq
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	jqCmd.Stdout = outFile

	// Capture stderr for both commands
	var stderr strings.Builder
	aliyunCmd.Stderr = &stderr
	jqCmd.Stderr = &stderr

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, stderr.String())
	}
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Wait() // Ensure first command is cleaned up
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, stderr.String())
	}

	// Wait for commands to complete
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	// Check for errors
	if aliyunErr != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, stderr.String())
	}
	if jqErr != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, stderr.String())
	}

	// Read the contents of the output file to return
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(content), nil
}

