// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// First command: aliyun slb DescribeLoadBalancers
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}

	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stderr pipe for aliyun command: %w", err)
	}

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Second command: jq
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout
	jqOutput, err := jqCmd.CombinedOutput()
	if err != nil {
		_ = aliyunCmd.Wait()
		// Capture aliyun's stderr
		aliyunErr := make([]byte, 1024)
		n, _ := aliyunStderr.Read(aliyunErr)
		return string(jqOutput) + string(aliyunErr[:n]), fmt.Errorf("jq command failed: %w", err)
	}

	if err := aliyunCmd.Wait(); err != nil {
		aliyunErr := make([]byte, 1024)
		n, _ := aliyunStderr.Read(aliyunErr)
		return string(jqOutput) + string(aliyunErr[:n]), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Write output to file
	if err := os.WriteFile(outputFile, jqOutput, 0644); err != nil {
		return string(jqOutput), fmt.Errorf("failed to write to output file: %w", err)
	}

	return string(jqOutput), nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <loadBalancerName> <outputFile>")
		os.Exit(1)
	}

	name := os.Args[1]
	file := os.Args[2]

	output, err := QuerySLBAndExport(name, file)
	if err != nil {
		fmt.Printf("Error: %v\nOutput: %s\n", err, output)
		os.Exit(1)
	}

	fmt.Printf("Success\nOutput: %s\n", output)
}

