	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Execute aliyun slb DescribeLoadBalancers
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunOut, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}
	aliyunErrOut, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stderr pipe: %w", err)
	}

	// Execute jq to process the output
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunOut
	jqOut, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stdout pipe: %w", err)
	}
	jqErrOut, err := jqCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stderr pipe: %w", err)
	}

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Wait() // Ensure aliyunCmd is properly cleaned up
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Read stderr from both commands
	var aliyunErr, jqErr string
	go func() {
		buf, e := io.ReadAll(aliyunErrOut)
		if e != nil {
			aliyunErr = fmt.Sprintf("error reading aliyun stderr: %v", e)
		} else {
			aliyunErr = string(buf)
		}
	}()
	go func() {
		buf, e := io.ReadAll(jqErrOut)
		if e != nil {
			jqErr = fmt.Sprintf("error reading jq stderr: %v", e)
		} else {
			jqErr = string(buf)
		}
	}()

	// Write jq output to file
	outFile, err := os.Create(outputFile)
	if err != nil {
		aliyunCmd.Wait()
		jqCmd.Wait()
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	if _, err := io.Copy(outFile, jqOut); err != nil {
		aliyunCmd.Wait()
		jqCmd.Wait()
		return "", fmt.Errorf("failed to write to output file: %w", err)
	}

	// Wait for both commands to complete
	if err := jqCmd.Wait(); err != nil {
		aliyunCmd.Wait() // Ensure aliyunCmd is properly cleaned up
		var errStr string
		if jqErr != "" {
			errStr = ": " + jqErr
		}
		if aliyunErr != "" {
			errStr += "; aliyun error: " + aliyunErr
		}
		return "", fmt.Errorf("jq command failed: %w%s", err, errStr)
	}
	if err := aliyunCmd.Wait(); err != nil {
		var errStr string
		if aliyunErr != "" {
			errStr = ": " + aliyunErr
		}
		if jqErr != "" {
			errStr += "; jq error: " + jqErr
		}
		return "", fmt.Errorf("aliyun command failed: %w%s", err, errStr)
	}

	// Read the content of the output file to return it
	fileContent, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(fileContent), nil
}

